//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = function () {
  if (scwin.linkType == 'null' || scwin.linkType == '') {
    return false;
  }
  if (scwin.linkType == "MawbookingCreate") {
    scwin.f_Create();
    if (scwin.actionFlag == "Create") {
      ds_MasterBookingList.setCellData(0, 'ondt', scwin.p_ondt);
      ds_MasterBookingList.setCellData(0, 'fltno', scwin.p_fltno);
      ds_MasterBookingList.setCellData(0, 'dscd', scwin.p_dscd);
      ds_MasterBookingList.setCellData(0, 'dsnm', scwin.p_dsnm);
      ds_MasterBookingList.setCellData(0, 'shipgb', 'C');
      ds_MasterBookingList.setCellData(0, 'bookgb', 'B');
      ds_MasterBookingList.setCellData(0, 'srgb', 'N');
      ds_MasterBookingList.setCellData(0, 'lrgb', 'N');
      ds_MasterBookingList.setRowPosition(0);
      TotalRows.setValue(ds_MasterBookingList.getRowCount());
    }
  }
};
