scwin.f_EnablePopUpObj = function () {
  $c.gus.cfEnableObjects($p, [ed_avdt, ed_ondt, ed_mblno, ed_ontime, ed_avtime, ed_fltno, lc_srgb, lc_lrgb, ed_ctn, ed_gwht, ed_nrate, lc_shipgb, lc_bookgb]);
  $c.gus.cfEnableObjects($p, [udc_ca, udc_ed_lecd, udc_ed_cocd, udc_ed_dscd, udc_ed_dpcd, udc_wareCd]);
};
//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다.
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
  $c.gus.cfDisableObjects($p, [ed_avdt, ed_ondt, ed_mblno, ed_ontime, ed_avtime, ed_fltno, lc_srgb, lc_lrgb, ed_ctn, ed_gwht, ed_nrate, lc_shipgb, lc_bookgb]);
  $c.gus.cfDisableObjects($p, [udc_ca, udc_ed_lecd, udc_ed_cocd, udc_ed_dscd, udc_ed_dpcd, udc_wareCd]);
};
