scwin.f_Retrieve = function (gubun) {
  actionFlag = "Retrieve";
  switch (gubun) {
    case "Search":
      if ($c.gus.cfIsAfterDate($p, cnd_ed_ondtFrom.getValue(), cnd_ed_ondtTo.getValue()) == false) {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        cnd_ed_ondtFrom.focus();
        return false;
      }
      if (mblno.getValue().length < 11 && cnd_ed_ondtFrom.getValue() == "") {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_WRN_003, ["Onboard Date"]); //Onboard Date 를 선택해 주세요
        cnd_ed_ondtFrom.focus();
      } else {
        scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveBooking");
        ds_MasterBookingList.removeAll();
        ds_HouseBillList.removeAll();
        $c.sbm.execute($p, sbm_Retrieve);
        //             tr_Retrieve.Post();
      }
      break;
    case "Insert":
      scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveInsert");
      ds_MasterBookingList.removeAll();
      ds_HouseBillList.removeAll();
      $c.sbm.execute($p, sbm_Retrieve);
      //           tr_Retrieve.Post();
      break;
  }
};
