//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
  //신규버튼을 누르면 저장,업데이트 구분자를 저장으로 셋팅
  scwin.validSaveOrUpdate = 1;
  ds_HouseBillList.removeAll();
  scwin.f_ProcessBinding(ds_MasterBookingList, "SaveBookingList");
  scwin.f_Set("CREATE");
  scwin.processFlag = "Create";
  scwin.actionFlag = "Create";
  ed_mblno.focus();
};
//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
  //수정버튼을 누르면 update 구분자를 1로 셋팅
  scwin.actionFlag = "Update";
  scwin.validSaveOrUpdate = 0;
  scwin.f_Set("UPDATE");
};
//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = function () {
  // ds_MasterBookingList.getRowStatus()
  //   alert("getRowStatus ["+ds_MasterBookingList.getRowStatus(ds_MasterBookingList.getRowPosition())+"]");s
  if (ds_MasterBookingList.getModifiedIndex().length > 0) {
    if (ed_mblno.getValue() == "") {
      if (ed_cacd.getValue() == "") {
        $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Carrier Info"]);
        ed_cacd.focus();
        return false;
      }
      //Master Stock Number Loading 부분
      scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveStockNo");
      //tr_RetrieveMasterStockNo.Post();
      $c.sbm.execute($p, sbm_RetrieveMasterStockNo);
      scwin.f_Retrieve("Search"); //재조회
      scwin.BilltypeFlag = "N";
    }
    if (scwin.validSaveOrUpdate == 1) {
      if (scwin.BilltypeFlag == "N") {
        ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "bltype", "N");
      } else {
        ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "bltype", "G");
      }
    }
    if (scwin.f_ReqFieldChk()) {
      scwin.actionFlag = "Save";
      scwin.processFlag = "Save";
      scwin.f_SaveBinding();
      $c.sbm.execute($p, sbm_Save); //저장 실행
      //     tr_Save.Post();

      scwin.f_Set("SAVE");
    }
  } else {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["Master B/L No"]); /* @은(는) 변경된 사항이 없습니다. */
  }
}; //end if
//-------------------------------------------------------------------------
//저장값  바인딩
//-------------------------------------------------------------------------
scwin.f_SaveBinding = function () {
  ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "mblgb", "L");
  if (ed_lecd.getValue() != "" && lc_lrgb.getValue() == "R") {
    ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "mblgb", "O");
  }
};
//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
  scwin.validSaveOrUpdate = 0;
  if (scwin.processFlag == "Create") {
    ds_MasterBookingList.removeAll();
    scwin.f_Set("INIT");
    scwin.processFlag = "None";
  } else {
    scwin.f_Set("RETRIEVE");
  }
  ds_MasterBookingList.undoAll();
};
//유효성검사
scwin.f_ReqFieldChk = function () {
  if (ed_mblno.getValue() == "") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Master B/L No"]);
    ed_mblno.focus();
    return false;
  }
  if (ed_cacd.getValue() == "") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Carrier Info"]);
    ed_cacd.focus();
    return false;
  }
  if (ed_ondt.getValue() == "") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Onboard Date"]);
    ed_ondt.focus();
    return false;
  }
  if (ed_avdt.getValue() == "") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Arrival Date"]);
    ed_avdt.focus();
    return false;
  }
  //현재선택 되어있는 Combo 의 Code 값을  가져와 체크한다.
  if (ed_lecd.getValue() != "" && lc_lrgb.getValue() == "N") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Master Agent Type"]);
    lc_lrgb.focus();
    return false;
  }
  //현재선택 되어있는 Combo 의 Code 값을  가져와 체크한다.

  if (ed_cocd.getValue() != "" && lc_srgb.getValue() == "N") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Co_Load Agent Type"]);
    lc_srgb.focus();
    return false;
  }
  if ($c.gus.cfIsAfterDate($p, ed_ondt.getValue(), ed_avdt.getValue()) == false) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ed_ondt.focus();
    return false;
  }
  if (lc_shipgb.getValue() == "L") {
    if (ed_cocd.getValue().trim() == "") {
      $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_005); // "Shipment Type 이 Co_Load 일때 Co-Load 정보를 입력 하셔야 합니다.";
      ed_cocd.focus();
      return false;
    }
  }
  if ($c.gus.cfValidate($p, [tbl_MasterBookingInfo]) == false) {
    return false;
  }
  return true;
};
