/**
 * @method 
 * @name f_PopUpGrid 
 * @description 화면이동
 * @param {string} name
 */
scwin.f_OpenPgm = function (name) {
  let url, menuCode, menuNm, paramObj;
  switch (name) {
    case 'MAWB':
      if (lc_shipgb.getValue() == "C" || lc_shipgb.getValue() == "D") {
        url = '/ui/il/airout/aobl/ar_103_01_01b.xml';
        menuCode = 'ar_103_01_01b.xml';
        menuNm = 'Export Master B/L';
        paramObj = {
          'kcomcd': scwin.hd_kcomcd,
          'blno': ed_mblno.getValue(),
          'type': 'MawbCreate'
        };
        $c.win.openMenu($p, menuNm, url, menuCode, paramObj);
      }
      break;
    case 'HAWB':
      if (lc_shipgb.getValue() == "L") {
        url = '/ui/il/airout/aobl/ar_104_01_01b.xml';
        menuCode = 'ar_104_01_01b.xml';
        menuNm = 'Export House B/L';
        paramObj = {
          'kcomcd': scwin.hd_kcomcd,
          'mblno': ed_mblno.getValue(),
          'type': 'ColoadHawbCreate'
        };
        $c.win.openMenu($p, menuNm, url, menuCode, paramObj);
      }
      break;
    case 'SR':
      url = '/ui/il/airout/aobl/ar_101_01_01b.xml';
      menuCode = 'ar_104_01_02b.xml';
      menuNm = 'Shipping Request';
      paramObj = {
        'kcomcd': scwin.hd_kcomcd,
        'blno': ed_mblno.getValue()
      };
      $c.win.openMenu($p, menuNm, url, menuCode, paramObj);
      break;
    case 'HouseBill':
      url = '/ui/il/airout/aobl/ar_104_01_01b.xml';
      menuCode = 'ar_104_01_01b.xml';
      menuNm = 'Export House B/L';
      paramObj = {
        'kcomcd': ds_HouseBillList.getCellData(ds_HouseBillList.getRowPosition(), 'kcomcd'),
        'blno': ds_HouseBillList.getCellData(ds_HouseBillList.getRowPosition(), 'blno')
      };
      $c.win.openMenu($p, menuNm, url, menuCode, paramObj);
      break;
    default:
      break;
  }
  ;
};

//공통팝업 열기
scwin.f_OpenCommonPopUp = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
  var rtnList = new Array();
  switch (gubun1) {
    case "Warehouse":
      //Warehouse
      rtnList = udc_wareCd.ilCommonPopUp('retrieveAirBoneZoneCode' // XML상의 SELECT ID
      , ed_warecd.getValue().trim() // 화면에서의 ??? Code Element의	Value
      , txt_warenm.getValue() // 화면에서의 ??? Name Element의	Value
      , pWinCloseTF // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
      , '4' // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
      , "Code, Name,'',Eng" // Title순서
      , '80,200,0,60' // 보여주는 각 컬럼들의 폭
      , "3,5,6,7,8,9,10" // 컬럼중에서 숨기는	컬럼 지정
      , null // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , null // POP-UP뛰을때 원도우의	사용자 정의	폭
      , null // POP-UP뛰을때 우도우의	사용자 정의	높이
      , null // 윈도우 위치 Y좌표
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , pAllSearchTF // 전체검색허용여부	("F")
      , "Warehouse,Code,Name" // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      , pNoDataCloseTF // Data 건수가 0 일때 Window를 뛰우지 않음 리턴 : "N/A"
      );
      $c.gus.cfSetReturnValue($p, rtnList, ed_warecd, txt_warenm);
      break;
    default:
      break;
  }
};
