//  조회 TR EVENT(성공)
scwin.sbm_Retrieve_submitdone = function (e) {
  if (ds_MasterBookingList.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); //해당되는 자료가 존재하지 않습니다.
    cnd_ed_ondtFrom.focus();
    scwin.f_Set("INIT");
  } else {
    scwin.f_Set("RETRIEVE");
    scwin.processFlag = "Exist";
    ds_MasterBookingList.setRowPosition(0);
  }
  TotalRows.setValue(ds_MasterBookingList.getRowCount());

  //	$c.gus.cfShowTotalRows(TotalRows, ds_MasterBookingList.getRowCount());	
};
scwin.sbm_Retrieve_submiterror = function (e) {
  $c.gus.cfShowError($p, sbm_Retrieve);
};
//저장 callback
scwin.sbm_Save_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
    return;
  }
  if (scwin.processFlag == "Save") {
    $c.gus.cfAlertMsg($p, "Data was saved successfully."); // 성공적으로 저장하였습니다
    scwin.f_Retrieve("Search"); //재조회
  }
  if (scwin.processFlag == "Delete") {
    $c.gus.cfAlertMsg($p, "Data was deleted successfully."); // 성공적으로 삭제하였습니다
    scwin.f_Retrieve("Search"); //재조회
  }
  scwin.processFlag = "None";
  if (scwin.validSaveOrUpdate == 1) {
    scwin.f_Retrieve("Insert");
    scwin.validSaveOrUpdate = 0;
    if (ds_MasterStockNo.getRowCount() > 0 && scwin.BilltypeFlag == "N") {
      $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_004, [ds_MasterStockNo.getCellData(1, "ncnt")]); //현재 남은 B/L 수량은  @ 부 입니다."
      scwin.BilltypeFlag = "G";
    }
  }
  TotalRows.setValue(ds_MasterBookingList.getRowCount());
  //   $c.gus.cfShowTotalRows(TotalRows, ds_MasterBookingList.getRowCount());	
};
scwin.gr_MasterBookingList_oncellclick = function (rowIndex, columnIndex, columnId) {
  scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveHouse");
  ds_MasterBookingSearch.setCellData(0, 'mblno', ds_MasterBookingList.getCellData(ds_MasterBookingList.getRowPosition(), 'mblno'));
  ds_MasterBookingSearch.setCellData(0, 'mhno', ds_MasterBookingList.getCellData(ds_MasterBookingList.getRowPosition(), 'mhno'));
  $c.sbm.execute($p, sbm_RetrieveHouseBillList);
};
